import fs from "node:fs";
import net from "node:net";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("node:child_process", () => ({
    fork: vi.fn().mockReturnValue({
        unref: vi.fn(),
        pid: 12345,
    }),
}));
import { fork } from "node:child_process";
import { ensureDaemon } from "./ensure.js";
function tmpPath(prefix) {
    return path.join(os.tmpdir(), `bitfab-test-${prefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`);
}
describe("ensureDaemon", () => {
    let socketPath;
    let pidPath;
    let mockServer = null;
    beforeEach(() => {
        vi.clearAllMocks();
        vi.spyOn(fs, "existsSync").mockReturnValue(true);
        socketPath = `${tmpPath("ensure")}.sock`;
        pidPath = `${tmpPath("ensure")}.pid`;
    });
    afterEach(() => {
        if (mockServer) {
            mockServer.close();
            mockServer = null;
        }
        try {
            fs.unlinkSync(socketPath);
        }
        catch { }
        try {
            fs.unlinkSync(pidPath);
        }
        catch { }
        try {
            fs.unlinkSync(`${socketPath}.lock`);
        }
        catch { }
    });
    it("spawns daemon when PID file is missing", async () => {
        // Make fork actually start a mock server so waitForSocket succeeds
        vi.mocked(fork).mockImplementation(() => {
            mockServer = net.createServer((socket) => {
                let buffer = "";
                socket.on("data", (chunk) => {
                    buffer += chunk.toString();
                    if (buffer.includes("\n")) {
                        socket.write('{"ok":true}\n');
                        buffer = "";
                    }
                });
            });
            mockServer.listen(socketPath);
            return { unref: vi.fn(), pid: 12345 };
        });
        await ensureDaemon(socketPath, pidPath);
        expect(fork).toHaveBeenCalledOnce();
    });
    it("reuses daemon when PID is alive and socket responds", async () => {
        // Write a PID file with current process PID (so it's "alive")
        fs.writeFileSync(pidPath, `${process.pid}\n`);
        // Start a mock server that responds to ping
        mockServer = net.createServer((socket) => {
            let buffer = "";
            socket.on("data", (chunk) => {
                buffer += chunk.toString();
                if (buffer.includes("\n")) {
                    socket.write('{"ok":true}\n');
                    buffer = "";
                }
            });
        });
        await new Promise((resolve) => {
            mockServer.listen(socketPath, resolve);
        });
        await ensureDaemon(socketPath, pidPath);
        expect(fork).not.toHaveBeenCalled();
    });
    it("cleans up stale PID file and respawns", async () => {
        // Write PID file with a dead PID
        fs.writeFileSync(pidPath, "999999999\n");
        vi.mocked(fork).mockImplementation(() => {
            mockServer = net.createServer((socket) => {
                let buffer = "";
                socket.on("data", (chunk) => {
                    buffer += chunk.toString();
                    if (buffer.includes("\n")) {
                        socket.write('{"ok":true}\n');
                        buffer = "";
                    }
                });
            });
            mockServer.listen(socketPath);
            return { unref: vi.fn(), pid: 12345 };
        });
        await ensureDaemon(socketPath, pidPath);
        expect(fork).toHaveBeenCalledOnce();
    });
});
